-  }
-  if (json_pointer[escape + 1] != '0' && json_pointer[escape + 1] != '1') {
-    return false;
+  while (escape != std::string_view::npos) {
+    if (escape == json_pointer.size() - 1) {
+      return false;
+    }
+    if (json_pointer[escape + 1] != '0' && json_pointer[escape + 1] != '1') {
+      return false;
+    }
+    escape = json_pointer.find('~', escape + 1);
   }
   return true;
 }
